fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut nums = nums;
    nums.sort();
    let n = nums.len();
    let mut min_removal = i64::MAX;

    for i in 0..n {
        let target = nums[i] * k;
        let mut left = i;
        let mut right = n;
        let mut best_j = i;

        while left < right {
            let mid = left + (right - left) / 2;
            if nums[mid] <= target {
                best_j = mid;
                left = mid + 1;
            } else {
                right = mid;
            }
        }

        let current_removal = (i + (n - 1 - best_j)) as i64;
        if current_removal < min_removal {
            min_removal = current_removal;
        }
    }

    min_removal
}
